def ply_based_discount(evaluations: list, ply_depths: list, gamma: float) -> tuple:
    discounted_values = [
        round(eval_score * (gamma ** depth), 4)
        for eval_score, depth in zip(evaluations, ply_depths)
    ]
    best_index = discounted_values.index(max(discounted_values))
    return (discounted_values, best_index)
